/**
 * Feature flag keys
 */
export type FeatureKey =
  | 'digitalMenu'
  | 'qrCodeGeneration'
  | 'basicAnalytics'
  | 'emenumWatermark'
  | 'customDomain'
  | 'whiteLabel'
  | 'orderReceiving'
  | 'kitchenDisplay'
  | 'waiterApp'
  | 'tableManagement'
  | 'serviceRequests'
  | 'aiContentGen'
  | 'aiImageGen'
  | 'aiTranslation'
  | 'aiInsights'
  | 'aiForecasting'
  | 'aiNaturalQuery'
  | 'multiBranch'
  | 'centralMenuMgmt'
  | 'campaigns'
  | 'loyaltyProgram'
  | 'apiAccess'
  | 'webhooks'
  | 'customIntegrations'
  | 'prioritySupport'
  | 'dedicatedAccount'
  | 'slaGuarantee';

// -----------------------------------------------------------------------------
// Plan Configuration
// -----------------------------------------------------------------------------

/**
 * Subscription plan information
 */
