  | 'contentImprovement'
  | 'seoOptimization'
  | 'stockPhotoSearch'
  | 'imageGenerationBasic'
  | 'imageGenerationHd'
  | 'naturalLanguageQuery'
  | 'analyticsInsight'
  | 'demandForecast'
  | 'anomalyDetection'
  | 'chatbotResponse';

