  name: {
    menu: { min: 1, max: 100 },
    product: { min: 1, max: 150 },
    category: { min: 1, max: 100 },
    organization: { min: 2, max: 100 },
    user: { min: 2, max: 100 },
  },

  /**
   * Slug constraints
   */
  slug: {
    min: 3,
    max: 50,
    pattern: /^[a-z0-9-]+$/,
  },

  /**
   * Description fields
   */
  description: {
    full: { min: 0, max: 2000 },
    short: { min: 0, max: 100 },
  },

  /**
   * Contact fields
   */
  email: { min: 5, max: 255 },
  phone: { min: 10, max: 15, pattern: /^\+?[0-9]+$/ },

  /**
   * Password requirements
   */
  password: {
    min: 8,
    max: 128,
    requireUppercase: true,
    requireLowercase: true,
    requireNumber: true,
  },

  /**
   * Numeric constraints
   */
  price: { min: 0.01, max: 999999.99, precision: 2 },
  quantity: { min: 1, max: 999 },
  sortOrder: { min: 0, max: 9999 },
  calories: { min: 0, max: 99999 },
  preparationTime: { min: 1, max: 180 },
  spicyLevel: { min: 0, max: 5 },
  tableCapacity: { min: 1, max: 50 },

  /**
   * Array constraints
   */
  tags: { maxItems: 10, itemMaxLength: 30 },
  gallery: { maxItems: 10 },
  allergens: { maxItems: 14 },

  /**
   * File upload constraints
   */
  upload: {
    productImage: {
      maxSizeBytes: 5 * 1024 * 1024, // 5MB
      allowedTypes: ['image/jpeg', 'image/png', 'image/webp'],
      minWidth: 400,
      minHeight: 400,
    },
    logo: {
      maxSizeBytes: 2 * 1024 * 1024, // 2MB
      allowedTypes: ['image/jpeg', 'image/png', 'image/svg+xml'],
      recommendedWidth: 200,
      recommendedHeight: 200,
    },
    menuBackground: {
      maxSizeBytes: 10 * 1024 * 1024, // 10MB
      allowedTypes: ['image/jpeg', 'image/png'],
      minWidth: 1920,
